import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

const repoRoot = resolve(import.meta.dirname, "..");
const packageDir = resolve(repoRoot, "packages/japanpost-react");
const docsDir = resolve(packageDir, "docs");
const englishPath = resolve(docsDir, "README.en.md");
const koreanPath = resolve(docsDir, "README.ko.md");
const englishOutputPath = resolve(packageDir, "README.md");
const koreanOutputPath = resolve(packageDir, "README.ko.md");

const generatedNotice =
  "<!-- This file is generated by `pnpm readme:package`. Edit docs/README.en.md and docs/README.ko.md instead. -->";

async function loadTrimmed(path) {
  const content = await readFile(path, "utf8");
  return content.trim();
}

async function loadExisting(path) {
  try {
    return await readFile(path, "utf8");
  } catch (error) {
    if (
      typeof error === "object" &&
      error !== null &&
      "code" in error &&
      error.code === "ENOENT"
    ) {
      return null;
    }

    throw error;
  }
}

function buildOutput(source, languageLink) {
  const [heading, ...bodyLines] = source.split("\n");
  const body = bodyLines.join("\n").trim();

  return [heading, "", languageLink, "", generatedNotice, "", body, ""].join(
    "\n",
  );
}

const [english, korean] = await Promise.all([
  loadTrimmed(englishPath),
  loadTrimmed(koreanPath),
]);

const englishOutput = buildOutput(english, "[한국어 README](./README.ko.md)");
const koreanOutput = buildOutput(korean, "[English README](./README.md)");

if (process.argv.includes("--check")) {
  const [existingEnglish, existingKorean] = await Promise.all([
    loadExisting(englishOutputPath),
    loadExisting(koreanOutputPath),
  ]);

  if (existingEnglish !== englishOutput) {
    console.error(
      `Generated content does not match ${englishOutputPath}. Run pnpm readme:package.`,
    );
    process.exit(1);
  }

  if (existingKorean !== koreanOutput) {
    console.error(
      `Generated content does not match ${koreanOutputPath}. Run pnpm readme:package.`,
    );
    process.exit(1);
  }

  console.log(`Verified ${englishOutputPath}`);
  console.log(`Verified ${koreanOutputPath}`);
} else {
  await Promise.all([
    writeFile(englishOutputPath, englishOutput),
    writeFile(koreanOutputPath, koreanOutput),
  ]);
  console.log(`Generated ${englishOutputPath}`);
  console.log(`Generated ${koreanOutputPath}`);
}
